const items = $input.all();
const today = new Date().toISOString().slice(0, 10);

const lines = items.map(function(item) {
  const d = item.json;
  return '- *' + d.account_name + '* (' + d.account_id + ')\n  Plan: ' + d.plan_name + ' | Model: ' + d.charge_model + '\n  Configured: $' + d.configured_fee + ' | Invoiced: $' + d.total_invoiced + ' | Delta: $' + d.delta;
});

const text =
  ':warning: *Payment Gateway Fee Reconciliation Alert* -- ' + today + '\n\n' +
  '*' + items.length + ' account(s) have mismatched payment gateway fees in the last 30 days:*\n\n' +
  lines.join('\n\n') +
  '\n\n_Sorted by largest discrepancy. Max 50 results shown._';

return [{ json: { slackText: text } }];
